#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2005;
int dp[N][N],a[N],n;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	while(cin>>n)
	{
		for(int i=1;i<=n;i++)
		{
			cin>>a[i];
		}
		memset(dp,0x3f,sizeof(dp));
		dp[1][1]=0;
		for(int i=2;i<=n;i++)
		{
			for(int j=2;j<=i;j++)
			{
				if(a[i-1]<a[i]) dp[i][j]=min(dp[i-1][j-1],dp[i][j]);
				if(dp[i-1][j-1]<a[i]) dp[i][i-j+1]=min(a[i-1],dp[i][i-j+1]);
			}
		}
		if(dp[n][n/2]==0x3f3f3f3f) cout<<"No!\n";
		else cout<<"Yes!\n";
	}
	return 0;
}
